import React, { useState } from "react";
import Login from "./components/Login/Login";
import Dashboard from "./components/Dashboard/Dashboard";
import Documents from "./components/Documents/Documents";
import Workflow from "./components/Workflow/Workflow";
import Users from "./components/Users/Users";
import Reports from "./components/Reports/Reports";
import Transcription from "./components/Transcription/Transcription"; // 🔑 NOUVELLE IMPORTATION
import Footer from "./components/common/Footer";
import Header from "./components/common/Header";
import TabNavigation from "./components/common/TabNavigation";
import MediaLibrary from './components/MediaLibrary/MediaLibrary';

// 🔑 AJOUT DE L'ONGLET "Transcription" DANS LE MENU
const TABS = [
  { key: "dashboard", label: "Tableau de bord" },
  { key: "documents", label: "Documents" },
  { key: "transcription", label: "Transcription" }, // 🔑 NOUVEL ONGLET
  { key: "workflow", label: "Workflow" },
  { key: "users", label: "Utilisateurs" },
  { key: "reports", label: "Rapports" },
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState("dashboard");
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentView, setCurrentView] = useState<'documents' | 'media-library'>('documents');
  const handleLoginSuccess = () => {
    setIsAuthenticated(true);
  };

  const renderTabContent = () => {
    switch (activeTab) {
      case "dashboard":
        return <Dashboard />;
      case "documents":
        return currentView === 'documents' ? (
          <Documents onNavigateToMediaLibrary={() => setCurrentView('media-library')} />
        ) : (
          <MediaLibrary onBack={() => setCurrentView('documents')} />
        );
      case "transcription": // 🔑 NOUVEAU CAS
        return <Transcription />;
      case "workflow":
        return <Workflow />;
      case "users":
        return <Users />;
      case "reports":
        return <Reports />;
      default:
        return null;
    }
  };

  if (!isAuthenticated) {
    return <Login onLoginSuccess={handleLoginSuccess} />;
  }

  return (
    <div className="min-h-screen flex flex-col bg-gray-50 dark:bg-gray-900 text-gray-900 dark:text-gray-100">
      <Header />
      <main className="flex-1 container mx-auto px-4 py-6">
        <TabNavigation
          tabs={TABS.map((t) => t.label)}
          activeTab={TABS.find((t) => t.key === activeTab)?.label || ""}
          onTabChange={(label) => {
            const found = TABS.find((t) => t.label === label);
            if (found) setActiveTab(found.key);
          }}
        />
        <div className="mt-6">{renderTabContent()}</div>
      </main>
      <Footer />
    </div>
  );
};

export default App;
